    uint32_t K = w_shape->GetOriginShape().GetDim(2); // assume depth = height = width

    // Assume stride=1, padding=0, dilation=1
    uint32_t Dout = D - K + 1;
    uint32_t Hout = H - K + 1;
    uint32_t Wout = W - K + 1;

    uint32_t totalLength = N * Cout * Dout * Hout * Wout;

    // UB budget: we need to store weight (Cout*C*K*K*K floats) and a tile of output elements' input patches
    // For simplicity, use a fixed tile length
    uint32_t maxTile = (UB_BUDGET_BYTES / (sizeof(float) * (C * K * K * K + 1))) / 4; // heuristic
    if (maxTile < 1) maxTile = 1;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLen = maxTile;
    if (tileLen > totalLength) tileLen = totalLength;

    uint32_t blockDim = 8; // fixed for simplicity, could be adaptive
    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_C(C);
    tiling.set_D(D);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_Cout(Cout);
    tiling.set_K(K);
